--- 正在进行初始尝试 ---&quot;) initial_prompt = INITIAL_PROMPT_TEMPLATE.format(task=task) initial_code = self._get_llm_response(initial_prompt) self.memory.add_record(&quot;execution&quot;, initial_code) # --- 2. 迭代循环:反思与优化 --- for i in range(self.max_iterations): print(f&quot;
--- 第 &#123;i+1&#125;/&#123;self.max_iterations&#125; 轮迭代 ---&quot;) # a. 反思 print(&quot;
-&gt; 正在进行反思...&quot;) last_code = self.memory.get_last_execution() reflect_prompt = REFLECT_PROMPT_TEMPLATE.format(task=task, code=last_code) feedback = self._get_llm_response(reflect_prompt) self.memory.add_record(&quot;reflection&quot;, feedback) # b. 检查是否需要停止 if &quot;无需改进&quot; in feedback: print(&quot;
✅ 反思认为代码已无需改进，任务完成。&quot;) break # c. 优化 print(&quot;
-&gt; 正在进行优化...&quot;) refine_prompt = REFINE_PROMPT_TEMPLATE.format( task=task, last_code_attempt=last_code, feedback=feedback ) refined_code = self._get_llm_response(refine_prompt) self.memory.add_record(&quot;execution&quot;, refined_code) final_code = self.memory.get_last_execution() print(f&quot;
