essages.create( model=MODEL, system=SYSTEM, messages=messages, tools=PARENT_TOOLS, max_tokens=8000, ) messages.append(&#123;&quot;role&quot;: &quot;assistant&quot;, &quot;content&quot;: response.content&#125;) if response.stop_reason != &quot;tool_use&quot;: return results = [] for block in response.content: if block.type == &quot;tool_use&quot;: # 当工具调用输出为task时，即subagent的工具时，会调用写好的subagent的代码 if block.name == &quot;task&quot;: desc = block.input.get(&quot;description&quot;, &quot;subtask&quot;) print(f&quot;&gt; task (&#123;desc&#125;): &#123;block.input[&#x27;prompt&#x27;][:80]&#125;&quot;) output = run_subagent(block.input[&quot;prompt&quot;]) else: handler = TOOL_HANDLERS.get(block.name) output = handler(**block.input) if handler else f&quot;Unknown tool: &#123;block.name&#125;&quot; print(f&quot; &#123;str(output)[:200]&#125;&quot;) results.append(&#123;&quot;type&quot;: &quot;tool_result&quot;, &quot;tool_use_id&quot;: block.id, &quot;content&quot;: str(output)&#125;) messages.append(&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: results&#125;) subagent代码和主agent代码一样,也是一个agentloop 1234567891011121314151617181920# -- Subagent: fresh context, filtered tools, summary-only return --def run_subagent(prompt: str) -&gt; str: sub_messages = [&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: prompt&#125;] # fresh context for _ in range(30): # safety limit response = client.messages.create( model=MODEL, system=SUBAGENT_SYSTEM, messages=sub_messages, tools=CHILD_TOOLS, max_tokens=8000, ) sub_messages.append(&#123;&quot;role&quot;: &quot;assistant&quot;, &quot;content&quot;: response.content&#125;) if response.stop_reason != &quot;tool_use&quot;: break results = [] for block in response.content: if block.type == &quot;tool_use&quot;: handler = TOOL_HANDLERS.get(block.name) output = handler(**block.input) if handler else f&quot;Unknown tool: &#123;block.name&#125;&quot; results.append(&#123;&quot;type&quot;: &quot;tool_result&quot;, &quot;tool_use_id&quot;: block.id, &quot;content&quot;: str(output)[:50000]&#125;) sub_messages.append(&#123;&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: results&#125;) # Only the final text returns to the parent -- child context is discarded return &quot;&quot;.join(b.text for b in response.content if hasattr(b, &quot;text&quot;)) or &quot;(no summary)&quot; 压缩上下文(s06小节) 其实，也一样，造一个compact的tool给到llm调用即可 123456789101112131415161718192021222324def auto_compact(messages: list) -&gt; list: # Save full transcript to disk TRANSCRIPT_DIR.mkdir(exist_ok=True) transcript_path = TRANSCRIPT_DIR / f&quot;transcript_&#123;int(time.time())&#125;.jsonl&quot; with open(transcript_path, &quot;w&quot;) as f: for msg in messages: f.write(json.dumps(msg, default=str) + &quot;
